/**
 * An x/y coordinate pair. Could be used to represent a screen point or a
 * vector.
 *
 * @since 5.0
 */
export interface Vector {
  /**
   * X coordinate
   *
   * @since 5.0
   */
  readonly x: number;
  /**
   * Y coordinate
   *
   * @since 5.0
   */
  readonly y: number;
}

/** @since 5.0 */
export type DirectionalPadAngle = -45 | 0 | 45 | -90 | 90 | -135 | 180 | 135;